class Solution {
    public boolean isFascinating(int n) {
        String concat = n + "" + (2 * n) + "" + (3 * n);
        boolean[] seen = new boolean[10];
        for (char c : concat.toCharArray()) {
            int digit = c - '0';
            if (digit == 0 || seen[digit]) return false;
            seen[digit] = true;
        }
        for (int i = 1; i <= 9; i++) {
            if (!seen[i]) return false;
        }
        return true;
    }
}
